if statement.code:
const age = 21

if (age >= 21) {
	output('have a drink')
}

logical operators.code:
const country = 'US'
const age = 18

if (country === 'US' && age >= 21) {
	output('have a drink')
}

else if.code:
const country = 'JP'
const age = 20

if (country === 'US' && age >= 21) {
	output('have a local US brew')
} else if (country === 'JP' && age >= 20) {
	output('have a local Japanese brew')
} else if (country === 'AU' && age >= 18) {
	output('have a local Austrailian brew')
} else {
	output('sorry, no brew for you')
}

while.code:
let i = 0
while (i < 3) {
	output(`i is now ${i}`)
	i++
}

output('done')

for.code:
for (let i = 0; i < 10; i++) {
	output(`i is now ${i}`)
}

output('done')

functions.code:
function greet (name) {
	const message = `hello there, ${name}!`
	output(message)
}

greet('Nick')

pure functions.code:
function square (num) {
	const x = num * num
	return x
}

const a = square(5)  
output(a)

variable declaration.code:
const square = function (num) {
	const x = num * num
	return x
}

const a = square(5)  
output(a)

arrow functions.code:
const square = (num) => {
	const x = num * num
	return x
}

const a = square(5)  
output(a)
